import { Box, Center, Input} from "@chakra-ui/react";
import { InputProps } from "../../types/utils";


export const InputCard = (props: InputProps) => {
    return (
        <Box>
            <Center flexDirection='column' marginBottom='2rem' color='white' >
                <Input id={props.id} type={props.type} placeholder={props.label} value={props.value} onChange={props.onChange}
                w='80%'
                h='4rem'
                mt='2rem' 
                textAlign='center'
                color='#0F172A' 
                border='1px solid #000000' 
                borderRadius='25px' 
                padding='0.5rem' />
            </Center>
        </Box>
    );
}